    // ═══════════════════════════════════════════════════════════════════
    // FINDING 8: tx_anchor cumulative decrease edge cases
    // ═══════════════════════════════════════════════════════════════════

    mod tx_decrease {
        use crate::tx_anchor::*;
        #[test]
        fn decrease_max_pct_255_allows_100_percent() {
            // max_decrease_pct = 255, decrease = 100%
            // 1000 * 100 / 1000 = 100, 100 > 255 → false → Ok
            assert!(check_tx_cumulative_decrease(1000, 0, 255).is_ok());
        }

        #[test]
        fn decrease_mul_overflow_large_anchor() {
            // anchor = u64::MAX, current = 0, max_pct = 100
            // With u128 arithmetic: decrease * 100 fits, and equals max_pct * anchor
            let result = check_tx_cumulative_decrease(u64::MAX, 0, 100);
            assert!(result.is_ok(), "100% decrease with max_pct=100 should pass with u128");
        }

        #[test]
        fn decrease_mul_overflow_boundary() {
            // Largest anchor where decrease * 100 doesn't overflow:
            // u64::MAX / 100 = 184_467_440_737_095_516
            let anchor = u64::MAX / 100;
            let current = 0;
            // decrease = anchor, anchor * 100 ≤ u64::MAX (just barely)
            let result = check_tx_cumulative_decrease(anchor, current, 100);
            assert!(result.is_ok());
        }

        #[test]
        fn decrease_max_pct_0_no_decrease_allowed() {
            // Even 1 unit decrease should fail
            assert!(check_tx_cumulative_decrease(u64::MAX, u64::MAX - 1, 0).is_err());
        }

        #[test]
        fn decrease_anchor_1_current_0_pct_100() {
            // 100% decrease, budget = 100%
            assert!(check_tx_cumulative_decrease(1, 0, 100).is_ok());
        }

        #[test]
        fn decrease_anchor_1_current_0_pct_99() {
            // 100% decrease, budget = 99%
            // decrease=1, 1*100/1=100, 100 > 99 → err
            assert!(check_tx_cumulative_decrease(1, 0, 99).is_err());
        }

        #[test]
        fn decrease_rounding_small_values() {
            // anchor=3, current=2, decrease=1
            // Comparison-based: 1 * 100 = 100 vs 33 * 3 = 99
            // 100 > 99 → err (33.33% > 33%, correctly caught without truncation)
            assert!(check_tx_cumulative_decrease(3, 2, 33).is_err());

            // max_pct=34: 1 * 100 = 100 vs 34 * 3 = 102 → 100 <= 102 → Ok
            assert!(check_tx_cumulative_decrease(3, 2, 34).is_ok());

            // max_pct=32 → 100 > 96 → err
            assert!(check_tx_cumulative_decrease(3, 2, 32).is_err());
        }

        #[test]
        fn fingerprint_single_instruction() {
            use solana_program::instruction::{Instruction, AccountMeta};
            use solana_program::pubkey::Pubkey;

            let ix = Instruction {
                program_id: Pubkey::new_unique(),
                accounts: vec![AccountMeta::new_readonly(Pubkey::new_unique(), false)],
                data: vec![0xFF],
            };
            let fp = compute_tx_fingerprint_from_instructions(&[ix]);
            assert_ne!(fp, [0u8; 32]);
        }

        #[test]
        fn fingerprint_255_instructions() {
            use solana_program::instruction::{Instruction, AccountMeta};
            use solana_program::pubkey::Pubkey;

            let ixs: Vec<Instruction> = (0..255)
                .map(|i| Instruction {
                    program_id: Pubkey::new_unique(),
                    accounts: vec![],
                    data: vec![i as u8],
                })
                .collect();
            let fp = compute_tx_fingerprint_from_instructions(&ixs);
            assert_ne!(fp, [0u8; 32]);
        }

        #[test]
        fn write_anchor_snapshot_minimum_pda() {
            // Minimum size for 0 fields: FINGERPRINT_LEN + 1 = 33 bytes
            let mut pda = vec![0u8; FINGERPRINT_LEN + 1];
            let fp = [0xAA; 32];
            write_anchor_snapshot(&mut pda, &fp, &[]);
            assert_eq!(&pda[..32], &fp);
            assert_eq!(pda[FINGERPRINT_LEN], 0);
        }

        #[test]
        #[should_panic(expected = "PDA anchor section too small")]
        fn write_anchor_snapshot_one_byte_short() {
            let mut pda = vec![0u8; FINGERPRINT_LEN]; // 32 bytes, need 33
            let fp = [0xAA; 32];
            write_anchor_snapshot(&mut pda, &fp, &[]);
        }

        #[test]
        fn read_anchor_corrupted_field_count() {
            let mut pda = vec![0u8; ANCHOR_SECTION_SIZE];
            // Set field_count = MAX + 1 = 17
            pda[FINGERPRINT_LEN] = MAX_ANCHOR_FIELDS as u8 + 1;
            assert!(read_anchor_snapshot(&pda).is_err());
        }

        #[test]
        fn read_anchor_field_count_ok_but_data_short() {
            // Claim 1 field but don't have enough data
            let mut pda = vec![0u8; FINGERPRINT_LEN + 1 + FIELD_SIZE - 1]; // 1 byte short
            pda[FINGERPRINT_LEN] = 1;
            assert!(read_anchor_snapshot(&pda).is_err());
        }

        #[test]
        fn is_first_invocation_empty_pda() {
            let pda: [u8; 0] = [];
            let fp = [0; 32];
            assert!(is_first_sandbox_invocation(&pda, &fp));
        }

        #[test]
        fn read_stored_fingerprint_exactly_32_bytes() {
            let pda = [0xAB; 32];
            let fp = read_stored_fingerprint(&pda);
            assert_eq!(fp, Some([0xAB; 32]));
        }

        #[test]
        fn read_stored_fingerprint_31_bytes() {
            let pda = [0xAB; 31];
            assert_eq!(read_stored_fingerprint(&pda), None);
        }
    }

