        #[test]
        fn skip_borsh_vec_u32_max_elements() {
            let mut data = vec![0u8; 4];
            data[0..4].copy_from_slice(&u32::MAX.to_le_bytes());
            // u32::MAX elements * 8 bytes each = way too large for any real data
            let result = skip_borsh_vec_fixed(&data, 0, 8);
            // On 64-bit: u32::MAX * 8 = ~34GB, but end > data.len() catches it
            // On potential overflow: checked_mul handles it
            assert!(result.is_err());
        }

