        fn skip_borsh_vec_overflow_element_size() {
            let mut data = vec![0u8; 4];
            data[0..4].copy_from_slice(&2u32.to_le_bytes());
            // 2 elements * usize::MAX would overflow checked_mul
            let result = skip_borsh_vec_fixed(&data, 0, usize::MAX);
            assert!(result.is_err());
        }

