        fn skip_borsh_string_data_too_short() {
            let mut data = [0u8; 4];
            data[0..4].copy_from_slice(&10u32.to_le_bytes()); // claims 10 bytes
            // but only 4 bytes total
            assert!(skip_borsh_string(&data, 0).is_err());
        }

