    // ═══════════════════════════════════════════════════════════════════
    // POST-FIX R3: F-1 HWM floor boundary values
    //
    // The F-1 fix sets hwm_value = current_value when HWM decays to 0.
    // Test boundary inputs: current_value=1 (minimum floor),
    // current_value=u64::MAX, and current_value=0 (nothing to protect).
    // ═══════════════════════════════════════════════════════════════════

    mod f1_hwm_floor_boundaries {
        use crate::circuit_breaker::*;

        fn make_tvl_section(history_len: u16) -> (Vec<u8>, usize) {
            let buf_size =
                TVL_HEADER_SIZE + (history_len as usize) * TvlSnapshot::SERIALIZED_SIZE;
            let mut data = vec![0u8; buf_size];
            data[0..2].copy_from_slice(&history_len.to_le_bytes());
            (data, 0)
        }

        #[test]
        fn hwm_floor_current_value_1_minimum() {
            // After all entries expire, HWM decays to 0. R3 fix sets HWM = before_value.
            // With before_value=1, HWM becomes 1. Any drain to 0 is 100% decrease.
            let (mut data, off) = make_tvl_section(4);
            let budget = CategoryBudget {
                category: InstructionCategory::Withdrawal,
                max_decrease_bps: 9999, // 99.99%
            };

            // Record a value, then let it expire
            tvl_cliff_check(
                &mut data, off, 1_000_000, 1_000_000, 100, 1000, 50, 300,
                &budget, BreakerAction::RejectCurrent,
            ).unwrap();

            // Jump far ahead so all entries expire. before_value=1, current_value=1.
            let result = tvl_cliff_check(
                &mut data, off, 1, 1, 500, 5000, 50, 300,
                &budget, BreakerAction::RejectCurrent,
            );
            assert_eq!(result.unwrap(), BreakerResult::Ok);

            // HWM should now be 1
            let hwm = read_u64(&data, off + 4).unwrap();
            assert_eq!(hwm, 1);

            // Now drain to 0: 100% decrease > 99.99% budget → should fire
            let result = tvl_cliff_check(
                &mut data, off, 1, 0, 501, 5001, 50, 300,
                &budget, BreakerAction::RejectCurrent,
            );
            assert!(result.is_err(), "100% drain from floor=1 should trigger breaker");
        }

        #[test]
        fn hwm_floor_current_value_u64_max() {
            // After expiry, HWM=0. R3 fix sets HWM = before_value = u64::MAX.
            // Subsequent decrease check uses u128 BPS, must not overflow.
            let (mut data, off) = make_tvl_section(4);
            let budget = CategoryBudget {
                category: InstructionCategory::Withdrawal,
                max_decrease_bps: 1500, // 15%
            };

            // Record and expire
            tvl_cliff_check(
                &mut data, off, 100, 100, 100, 1000, 50, 300,
                &budget, BreakerAction::RejectCurrent,
            ).unwrap();

            // Jump ahead, before_value = u64::MAX, current_value = u64::MAX
            let result = tvl_cliff_check(
                &mut data, off, u64::MAX, u64::MAX, 500, 5000, 50, 300,
                &budget, BreakerAction::RejectCurrent,
            );
            assert_eq!(result.unwrap(), BreakerResult::Ok);

            // HWM should be u64::MAX now
            let hwm = read_u64(&data, off + 4).unwrap();
            assert_eq!(hwm, u64::MAX);

            // Drop 20% from u64::MAX — BPS calc uses u128, should trigger
            let after = u64::MAX - u64::MAX / 5; // ~80% of u64::MAX
            let result = tvl_cliff_check(
                &mut data, off, after, after, 501, 5001, 50, 300,
                &budget, BreakerAction::RejectCurrent,
            );
            assert!(result.is_err(), "20% drop from u64::MAX should trigger 15% breaker");
        }

        #[test]
        fn hwm_floor_current_value_0_no_protection() {
            // Both HWM=0 and before_value=0 → R3 fix condition is
            // `hwm_value == 0 && before_value > 0`. Neither triggers.
            // Should be BreakerResult::Ok (nothing to protect).
            let (mut data, off) = make_tvl_section(4);
            let budget = CategoryBudget {
                category: InstructionCategory::Withdrawal,
                max_decrease_bps: 0, // strictest possible
            };

            // All entries expired, HWM=0, current=0
            tvl_cliff_check(
                &mut data, off, 100, 100, 100, 1000, 50, 300,
                &budget, BreakerAction::RejectCurrent,
            ).unwrap();

            // Jump ahead — before=0, current=0, HWM recalculates to 0
            let result = tvl_cliff_check(
                &mut data, off, 0, 0, 500, 5000, 50, 300,
                &budget, BreakerAction::RejectCurrent,
            );
            // HWM=0 and before_value=0: the `if hwm_value > 0 && current_value < hwm_value`
            // is false, breaker doesn't fire.
            assert_eq!(result.unwrap(), BreakerResult::Ok);
        }

        #[test]
        fn hwm_floor_then_increase_updates_hwm() {
            // After R3 sets floor HWM=before_value, a subsequent increase
            // should update HWM to the new higher value.
            let (mut data, off) = make_tvl_section(4);
            let budget = CategoryBudget {
                category: InstructionCategory::Withdrawal,
                max_decrease_bps: 1500,
            };

            // Expire entries
            tvl_cliff_check(
                &mut data, off, 100, 100, 100, 1000, 50, 300,
                &budget, BreakerAction::RejectCurrent,
            ).unwrap();

            // Jump ahead, floor set at 500 (before=500, current=500)
            tvl_cliff_check(
                &mut data, off, 500, 500, 500, 5000, 50, 300,
                &budget, BreakerAction::RejectCurrent,
            ).unwrap();

            // Increase to 1000 — HWM should update to 1000
            tvl_cliff_check(
                &mut data, off, 1000, 1000, 501, 5001, 50, 300,
                &budget, BreakerAction::RejectCurrent,
            ).unwrap();

            let hwm = read_u64(&data, off + 4).unwrap();
            assert_eq!(hwm, 1000, "HWM should update to new higher value after floor");
        }
    }

    // ═══════════════════════════════════════════════════════════════════
    // POST-FIX R3: F-2 Oracle owner backward compatibility
    //
    // read_oracle accepts expected_owner: Option<&Pubkey>.
    // None = skip check (backward compat). Some = strict check.
    // Verify the None path doesn't create a security hole for new code
    // that forgets to pass an owner.
    // ═══════════════════════════════════════════════════════════════════

    mod f2_oracle_owner_compat {
        use crate::oracle::*;
        use solana_program::{clock::Epoch, pubkey::Pubkey, system_program};
        use solana_program::account_info::AccountInfo;

        fn make_oracle_data(layout: &OracleLayout, price: u64, slot: u64, ts: Option<i64>) -> Vec<u8> {
            let mut data = vec![0u8; 256];
            data[layout.price_offset..layout.price_offset + 8]
                .copy_from_slice(&price.to_le_bytes());
            data[layout.slot_offset..layout.slot_offset + 8]
                .copy_from_slice(&slot.to_le_bytes());
            if let (Some(ts_off), Some(t)) = (layout.timestamp_offset, ts) {
                data[ts_off..ts_off + 8].copy_from_slice(&t.to_le_bytes());
            }
            data
        }

        fn default_layout() -> OracleLayout {
            OracleLayout {
                price_offset: 16,
                price_size: 8,
                slot_offset: 24,
                timestamp_offset: Some(32),
            }
        }

        #[test]
        fn oracle_none_owner_accepts_any_account() {
            let layout = default_layout();
            let key = Pubkey::new_unique();
            let random_owner = Pubkey::new_unique();
            let mut lamports = 0u64;
            let mut data = make_oracle_data(&layout, 42_000, 100, Some(1_700_000_000));
            let info = AccountInfo::new(
                &key, false, false, &mut lamports, &mut data, &random_owner,
                false, Epoch::default(),
            );

            // None = skip owner check → accepts any owner
            let reading = read_oracle(&info, &layout, None).unwrap();
            assert_eq!(reading.price, 42_000);
        }

        #[test]
        fn oracle_some_wrong_owner_rejected() {
            let layout = default_layout();
            let key = Pubkey::new_unique();
            let actual_owner = Pubkey::new_unique();
            let expected_owner = Pubkey::new_unique();
            let mut lamports = 0u64;
            let mut data = make_oracle_data(&layout, 42_000, 100, None);
            let info = AccountInfo::new(
                &key, false, false, &mut lamports, &mut data, &actual_owner,
                false, Epoch::default(),
            );

            let result = read_oracle(&info, &layout, Some(&expected_owner));
            assert!(result.is_err(), "Wrong owner should be rejected");
        }

        #[test]
        fn oracle_some_correct_owner_accepted() {
            let layout = default_layout();
            let key = Pubkey::new_unique();
            let owner = system_program::id();
            let mut lamports = 0u64;
            let mut data = make_oracle_data(&layout, 42_000, 100, None);
            let info = AccountInfo::new(
                &key, false, false, &mut lamports, &mut data, &owner,
                false, Epoch::default(),
            );

            let reading = read_oracle(&info, &layout, Some(&owner)).unwrap();
            assert_eq!(reading.price, 42_000);
        }

        #[test]
        fn validate_oracle_owner_empty_allowlist_accepts_all() {
            // Backward compat: empty allowlist = no check
            let layout = default_layout();
            let key = Pubkey::new_unique();
            let owner = Pubkey::new_unique();
            let mut lamports = 0u64;
            let mut data = make_oracle_data(&layout, 100, 100, None);
            let info = AccountInfo::new(
                &key, false, false, &mut lamports, &mut data, &owner,
                false, Epoch::default(),
            );
            // R3-2 fix: empty allowlist now fails closed
            assert!(validate_oracle_owner(&info, &[]).is_err());
        }

        #[test]
        fn oracle_price_zero_accepted() {
            // Edge: oracle returns price=0 (should not crash)
            let layout = default_layout();
            let key = Pubkey::new_unique();
            let owner = system_program::id();
            let mut lamports = 0u64;
            let mut data = make_oracle_data(&layout, 0, 100, None);
            let info = AccountInfo::new(
                &key, false, false, &mut lamports, &mut data, &owner,
                false, Epoch::default(),
            );
            let reading = read_oracle(&info, &layout, None).unwrap();
            assert_eq!(reading.price, 0);
        }

        #[test]
        fn oracle_no_timestamp_field() {
            let layout = OracleLayout {
                price_offset: 16,
                price_size: 8,
                slot_offset: 24,
                timestamp_offset: None,
            };
            let key = Pubkey::new_unique();
            let owner = system_program::id();
            let mut lamports = 0u64;
            let mut data = make_oracle_data(&layout, 999, 50, None);
            let info = AccountInfo::new(
                &key, false, false, &mut lamports, &mut data, &owner,
                false, Epoch::default(),
            );
            let reading = read_oracle(&info, &layout, None).unwrap();
            assert_eq!(reading.last_timestamp, None);
        }

        #[test]
        fn oracle_price_size_not_8_rejected() {
            // price_size must be 8
            let layout = OracleLayout {
                price_offset: 16,
                price_size: 4, // wrong
                slot_offset: 24,
                timestamp_offset: None,
            };
            let key = Pubkey::new_unique();
            let owner = system_program::id();
            let mut lamports = 0u64;
            let mut data = vec![0u8; 256];
            let info = AccountInfo::new(
                &key, false, false, &mut lamports, &mut data, &owner,
                false, Epoch::default(),
            );
            assert!(read_oracle(&info, &layout, None).is_err());
        }
    }

