        #[test]
        fn event_counter_max_values_roundtrip() {
            let mut state = SandboxState::new(1);
            state.event_counters = EventCounterState {
                counters: vec![EventCounter {
                    counter_id: 255,
                    count: u32::MAX,
                    window_start_slot: u64::MAX,
                    window_start_timestamp: i64::MAX,
                }],
            };
            let size = state.total_size().unwrap();
            let mut buf = vec![0u8; size];
            state.serialize(&mut buf).unwrap();
            let decoded = SandboxState::deserialize(&buf).unwrap();
            let ec = &decoded.event_counters.counters[0];
            assert_eq!(ec.counter_id, 255);
            assert_eq!(ec.count, u32::MAX);
            assert_eq!(ec.window_start_slot, u64::MAX);
            assert_eq!(ec.window_start_timestamp, i64::MAX);
        }

        #[test]
        fn event_counter_section_size_calculation() {
            // Verify section size = 1 + 21 * count
            let mut state = SandboxState::new(1);
            state.event_counters = EventCounterState {
                counters: vec![
                    EventCounter { counter_id: 0, count: 0, window_start_slot: 0, window_start_timestamp: 0 },
                    EventCounter { counter_id: 1, count: 0, window_start_slot: 0, window_start_timestamp: 0 },
                ],
            };
            let size_with_2 = state.total_size().unwrap();

            state.event_counters = EventCounterState { counters: vec![] };
            let size_with_0 = state.total_size().unwrap();

            // Difference should be 2 * 21 = 42
            assert_eq!(size_with_2 - size_with_0, 42);
        }
