    // ═══════════════════════════════════════════════════════════════════
    // POST-FIX R3: F-6 u128 BPS boundary comparisons
    //
    // Verify the `decrease_bps > budget.max_decrease_bps as u128`
    // comparison works correctly at u64 boundaries.
    // ═══════════════════════════════════════════════════════════════════

    mod f6_u128_bps_boundaries {
        use crate::circuit_breaker::*;

        #[test]
        fn bps_u64_max_decrease_from_1() {
            // hwm=u64::MAX, current=0, decrease=u64::MAX
            // decrease_bps = u64::MAX * 10000 / u64::MAX = 10000
            // budget=10000 (100%) → 10000 > 10000 = false → Ok
            let result = per_tx_threshold_check(
                u64::MAX, 0, 10_000, BreakerAction::RejectCurrent,
            );
            assert_eq!(result.unwrap(), BreakerResult::Ok);
        }

        #[test]
        fn bps_u64_max_decrease_budget_9999() {
            // 100% decrease, budget=9999 bps (99.99%)
            // 10000 > 9999 → fires
            let result = per_tx_threshold_check(
                u64::MAX, 0, 9999, BreakerAction::RejectCurrent,
            );
            assert!(result.is_err());
        }

        #[test]
        fn bps_large_value_exact_boundary() {
            // before=10^18 (1 SOL in lamports with 18 decimals), after=85% of it
            // decrease=15% exactly = 1500 bps, budget=1500
            let before: u64 = 1_000_000_000_000_000_000;
            let after: u64 = 850_000_000_000_000_000;
            let result = per_tx_threshold_check(
                before, after, 1500, BreakerAction::RejectCurrent,
            );
            assert_eq!(result.unwrap(), BreakerResult::Ok, "15% = 1500bps exactly at budget");
        }

        #[test]
        fn bps_large_value_one_lamport_over_below_bps_resolution() {
            // before=10^18, decrease is 15% + 1 lamport
            // 1 lamport on 10^18 is below BPS resolution (1 bps = 10^14 lamports)
            // decrease_bps = 150000000000000001 * 10000 / 10^18 = 1500 (truncated)
            // 1500 > 1500 is false → Ok (correct: below BPS resolution)
            let before: u64 = 1_000_000_000_000_000_000;
            let after: u64 = 850_000_000_000_000_000 - 1;
            let result = per_tx_threshold_check(
                before, after, 1500, BreakerAction::RejectCurrent,
            );
            assert_eq!(result.unwrap(), BreakerResult::Ok,
                "1 lamport over on 10^18 is below BPS resolution");
        }

        #[test]
        fn bps_large_value_meaningful_over() {
            // To actually trigger at 10^18, need > 1 BPS worth of extra decrease
            let before: u64 = 1_000_000_000_000_000_000;
            // 15.01% = 1501 bps decrease. Use u128 to avoid compile-time overflow.
            let after: u64 = (before as u128 - (before as u128 * 1501 / 10_000)) as u64;
            let result = per_tx_threshold_check(
                before, after, 1500, BreakerAction::RejectCurrent,
            );
            assert!(result.is_err(), "15.01% decrease should trigger 15% budget");
        }

        #[test]
        fn bps_budget_u64_max_allows_everything() {
            // max_decrease_bps = u64::MAX → any decrease should pass
            let result = per_tx_threshold_check(
                1_000_000, 0, u64::MAX, BreakerAction::RejectCurrent,
            );
            assert_eq!(result.unwrap(), BreakerResult::Ok);
        }

        #[test]
        fn bps_tvl_cliff_u128_large_values() {
            // Test that tvl_cliff_check handles large values correctly with u128 fix
            let history_len: u16 = 4;
            let buf_size = TVL_HEADER_SIZE + (history_len as usize) * TvlSnapshot::SERIALIZED_SIZE;
            let mut data = vec![0u8; buf_size];
            data[0..2].copy_from_slice(&history_len.to_le_bytes());

            let budget = CategoryBudget {
                category: InstructionCategory::Withdrawal,
                max_decrease_bps: 5001, // 50.01%
            };

            // Record u64::MAX / 2 as value
            let big_val = u64::MAX / 2;
            tvl_cliff_check(
                &mut data, 0, big_val, big_val, 100, 1000, 1500, 600,
                &budget, BreakerAction::RejectCurrent,
            ).unwrap();

            // Drop exactly 50% — should pass (50% < 50.01%)
            let after = big_val / 2;
            let result = tvl_cliff_check(
                &mut data, 0, after, after, 101, 1001, 1500, 600,
                &budget, BreakerAction::RejectCurrent,
            );
            assert_eq!(result.unwrap(), BreakerResult::Ok, "50% < 50.01% should pass with u128");
        }
    }

    // ═══════════════════════════════════════════════════════════════════
    // POST-FIX R3: F-8 Comparison-based decrease with max_decrease_pct=255
    //
    // check_tx_cumulative_decrease now uses comparison:
    //   decrease * 100 > max_decrease_pct * anchor_value
    // Test boundary when max_decrease_pct=255 (max u8).
    // ═══════════════════════════════════════════════════════════════════

    mod f8_comparison_decrease {
        use crate::tx_anchor::*;

        #[test]
        fn max_pct_255_allows_all() {
            // max_pct=255 means up to 255% decrease allowed (>100%, any decrease OK)
            // anchor=1000, current=0 → decrease=1000
            // lhs = 1000 * 100 = 100_000
            // rhs = 255 * 1000 = 255_000
            // 100_000 > 255_000 → false → Ok
            assert!(check_tx_cumulative_decrease(1000, 0, 255).is_ok());
        }

        #[test]
        fn max_pct_255_with_u64_max_anchor() {
            // anchor=u64::MAX, current=0 → decrease=u64::MAX
            // lhs = u64::MAX * 100 (u128)
            // rhs = 255 * u64::MAX (u128)
            // lhs < rhs → Ok
            assert!(check_tx_cumulative_decrease(u64::MAX, 0, 255).is_ok());
        }

        #[test]
        fn max_pct_100_with_100_pct_decrease() {
            // Exactly 100% decrease, budget=100 → should pass
            // lhs = anchor * 100, rhs = 100 * anchor → equal → passes
            assert!(check_tx_cumulative_decrease(1000, 0, 100).is_ok());
            assert!(check_tx_cumulative_decrease(u64::MAX, 0, 100).is_ok());
            assert!(check_tx_cumulative_decrease(1, 0, 100).is_ok());
        }

        #[test]
        fn max_pct_1_catches_1_point_1_percent() {
            // anchor=1000, current=989 → decrease=11, 1.1%
            // lhs = 11 * 100 = 1100
            // rhs = 1 * 1000 = 1000
            // 1100 > 1000 → fires
            assert!(check_tx_cumulative_decrease(1000, 989, 1).is_err());
        }

        #[test]
        fn max_pct_1_passes_exactly_1_percent() {
            // anchor=1000, current=990 → decrease=10, 1.0%
            // lhs = 10 * 100 = 1000
            // rhs = 1 * 1000 = 1000
            // 1000 > 1000 → false → Ok
            assert!(check_tx_cumulative_decrease(1000, 990, 1).is_ok());
        }

        #[test]
        fn max_pct_0_rejects_any_decrease() {
            // Special case: max_pct=0 → any decrease rejected via early check
            assert!(check_tx_cumulative_decrease(u64::MAX, u64::MAX - 1, 0).is_err());
            assert!(check_tx_cumulative_decrease(1, 0, 0).is_err());
        }

        #[test]
        fn max_pct_0_allows_no_change() {
            assert!(check_tx_cumulative_decrease(1000, 1000, 0).is_ok());
            assert!(check_tx_cumulative_decrease(0, 0, 0).is_ok());
        }

        #[test]
        fn comparison_avoids_truncation_small_anchor() {
            // anchor=7, current=6 → decrease=1, real pct=14.28%
            // Old division: 1*100/7 = 14 (truncated) → max_pct=14 would pass (wrong!)
            // New comparison: 1*100=100, 14*7=98 → 100 > 98 → correctly rejects
            assert!(check_tx_cumulative_decrease(7, 6, 14).is_err());
            // max_pct=15: 1*100=100, 15*7=105 → 100 > 105 → false → Ok
            assert!(check_tx_cumulative_decrease(7, 6, 15).is_ok());
        }

        #[test]
        fn comparison_u128_no_overflow_at_max() {
            // Largest possible: decrease=u64::MAX, anchor=u64::MAX
            // lhs = u64::MAX * 100 in u128
            // rhs = 100 * u64::MAX in u128
            // Equal → passes
            assert!(check_tx_cumulative_decrease(u64::MAX, 0, 100).is_ok());
        }
    }

    // ═══════════════════════════════════════════════════════════════════
    // POST-FIX R3: F-9 wrapping_add with history_len=1 (single entry)
    //
    // ring_buffer_push now uses wrapping_add then modulo history_len.
    // Test that a single-entry buffer works after many wraps.
    // ═══════════════════════════════════════════════════════════════════

    mod f9_wrapping_add_single_entry {
        use crate::circuit_breaker::*;

        #[test]
        fn wrapping_add_history_len_1_stays_at_0() {
            let buf_size = TvlSnapshot::SERIALIZED_SIZE;
            let mut data = vec![0u8; buf_size];

            let snap = TvlSnapshot { value: 42, slot: 1, timestamp: 100 };
            // history_index=0, push → wrapping_add(1) = 1, 1 % 1 = 0
            let new_idx = ring_buffer_push(&mut data, 0, 1, 0, &snap).unwrap();
            assert_eq!(new_idx, 0, "Single-entry always wraps to 0");

            // Push again from 0 → same result
            let snap2 = TvlSnapshot { value: 99, slot: 2, timestamp: 200 };
            let new_idx = ring_buffer_push(&mut data, 0, 1, 0, &snap2).unwrap();
            assert_eq!(new_idx, 0);

            // Verify latest value
            let read = ring_buffer_read(&data, 0, 1, 0).unwrap();
            assert_eq!(read.value, 99);
        }

        #[test]
        fn wrapping_add_history_index_u16_max_len_1() {
            // Start with history_index at u16::MAX
            let buf_size = TvlSnapshot::SERIALIZED_SIZE;
            let mut data = vec![0u8; buf_size];

            let snap = TvlSnapshot { value: 77, slot: 1, timestamp: 100 };
            // history_index=u16::MAX → u16::MAX % 1 = 0 (writes to slot 0)
            // next = u16::MAX.wrapping_add(1) = 0, 0 % 1 = 0
            let new_idx = ring_buffer_push(&mut data, 0, 1, u16::MAX, &snap).unwrap();
            assert_eq!(new_idx, 0);

            let read = ring_buffer_read(&data, 0, 1, 0).unwrap();
            assert_eq!(read.value, 77);
        }

        #[test]
        fn wrapping_add_history_index_u16_max_len_2() {
            let history_len: u16 = 2;
            let buf_size = (history_len as usize) * TvlSnapshot::SERIALIZED_SIZE;
            let mut data = vec![0u8; buf_size];

            let snap = TvlSnapshot { value: 55, slot: 1, timestamp: 100 };
            // history_index=u16::MAX → u16::MAX % 2 = 1 (writes to slot 1)
            // next = u16::MAX.wrapping_add(1) = 0, 0 % 2 = 0
            let new_idx = ring_buffer_push(&mut data, 0, history_len, u16::MAX, &snap).unwrap();
            assert_eq!(new_idx, 0);

            // Verify written at slot 1
            let read = ring_buffer_read(&data, 0, history_len, 1).unwrap();
            assert_eq!(read.value, 55);
        }

        #[test]
        fn wrapping_add_history_index_u16_max_minus_1_len_3() {
            let history_len: u16 = 3;
            let buf_size = (history_len as usize) * TvlSnapshot::SERIALIZED_SIZE;
            let mut data = vec![0u8; buf_size];

            let snap = TvlSnapshot { value: 33, slot: 1, timestamp: 100 };
            // history_index=65534 → 65534 % 3 = 1 (writes to slot 1)
            // next = 65534.wrapping_add(1) = 65535, 65535 % 3 = 0
            let new_idx = ring_buffer_push(&mut data, 0, history_len, u16::MAX - 1, &snap).unwrap();
            assert_eq!(new_idx, u16::MAX % 3);
        }

        #[test]
        fn wrapping_add_continuous_push_no_dos() {
            // Push many times with wrapping — should never fail
            let history_len: u16 = 3;
            let buf_size = (history_len as usize) * TvlSnapshot::SERIALIZED_SIZE;
            let mut data = vec![0u8; buf_size];

            let mut idx: u16 = 0;
            for i in 0..70_000u32 {
                let snap = TvlSnapshot {
                    value: i as u64,
                    slot: i as u64,
                    timestamp: i as i64,
                };
                idx = ring_buffer_push(&mut data, 0, history_len, idx, &snap).unwrap();
                assert!(idx < history_len, "Index must stay bounded");
            }
        }

        #[test]
        fn oldest_with_history_len_1_and_many_writes() {
            let buf_size = TvlSnapshot::SERIALIZED_SIZE;
            let mut data = vec![0u8; buf_size];

            // Push 5 times into single-entry buffer
            let mut idx: u16 = 0;
            for i in 0..5u64 {
                let snap = TvlSnapshot { value: (i + 1) * 100, slot: i, timestamp: i as i64 };
                idx = ring_buffer_push(&mut data, 0, 1, idx, &snap).unwrap();
            }

            // total_writes=5, history_len=1 → oldest = history_index % 1 = 0
            let oldest = ring_buffer_oldest(&data, 0, 1, idx, 5).unwrap();
            // Last written value is 500 (i=4)
            assert_eq!(oldest.value, 500);
        }
    }

